{
  "sentences": [
    {
      "text": "從車站到醫院怎麼去？",
      "pinyin": "Cóng chēzhàn dào yīyuàn zěnme qù?",
      "pinyin_numeric": "cong2 che1zhan4 dao4 yi1yuan4 zen3me qu4",
      "translation_en": "How do I get from the station to the hospital?",
      "translation_ko": "역에서 병원까지 어떻게 가나요?"
    },
    {
      "text": "從這裡到台北車站可以搭捷運嗎？",
      "pinyin": "Cóng zhèlǐ dào Táiběi chēzhàn kěyǐ dā jiéyùn ma?",
      "pinyin_numeric": "cong2 zhe4li3 dao4 Tai2bei3 che1zhan4 ke3yi3 da1 jie2yun4 ma0",
      "translation_en": "Can I take the MRT from here to Taipei Station?",
      "translation_ko": "여기에서 타이베이 역까지 지하철을 탈 수 있나요?"
    },
    {
      "text": "從學校到公園走路要幾分鐘？",
      "pinyin": "Cóng xuéxiào dào gōngyuán zǒulù yào jǐ fēnzhōng?",
      "pinyin_numeric": "cong2 xue2xiao4 dao4 gong1yuan2 zou3lu4 yao4 ji3 fen1zhong1",
      "translation_en": "How many minutes does it take to walk from school to the park?",
      "translation_ko": "학교에서 공원까지 걸어서 몇 분 걸리나요?"
    },
    {
      "text": "從圖書館到捷運站怎麼去？",
      "pinyin": "Cóng túshūguǎn dào jiéyùnzhàn zěnme qù?",
      "pinyin_numeric": "cong2 tu2shu1guan3 dao4 jie2yun4zhan4 zen3me qu4",
      "translation_en": "How do I get from the library to the MRT station?",
      "translation_ko": "도서관에서 지하철역까지 어떻게 가나요?"
    },
    {
      "text": "從我家到公司可以搭公車嗎？",
      "pinyin": "Cóng wǒ jiā dào gōngsī kěyǐ dā gōngchē ma?",
      "pinyin_numeric": "cong2 wo3 jia1 dao4 gong1si1 ke3yi3 da1 gong1che1 ma0",
      "translation_en": "Can I take the bus from my home to the company?",
      "translation_ko": "우리 집에서 회사까지 버스를 탈 수 있나요?"
    },
    {
      "text": "從這裡到夜市坐計程車大概要多少錢？",
      "pinyin": "Cóng zhèlǐ dào yèshì zuò jìchéngchē dàgài yào duōshao qián?",
      "pinyin_numeric": "cong2 zhe4li3 dao4 ye4shi4 zuo4 ji4cheng2che1 da4gai4 yao4 duo1shao qian2",
      "translation_en": "How much does it cost to take a taxi from here to the night market?",
      "translation_ko": "여기에서 야시장까지 택시를 타면 대략 얼마인가요?"
    },
    {
      "text": "從公園到學校要轉車嗎？",
      "pinyin": "Cóng gōngyuán dào xuéxiào yào zhuǎnchē ma?",
      "pinyin_numeric": "cong2 gong1yuan2 dao4 xue2xiao4 yao4 zhuan3che1 ma0",
      "translation_en": "Do I need to transfer from the park to the school?",
      "translation_ko": "공원에서 학교까지 환승해야 하나요?"
    },
    {
      "text": "從捷運站到餐廳怎麼去？",
      "pinyin": "Cóng jiéyùnzhàn dào cāntīng zěnme qù?",
      "pinyin_numeric": "cong2 jie2yun4zhan4 dao4 can1ting1 zen3me qu4",
      "translation_en": "How do I get from the MRT station to the restaurant?",
      "translation_ko": "지하철역에서 식당까지 어떻게 가나요?"
    },
    {
      "text": "從醫院到車站搭公車要幾站？",
      "pinyin": "Cóng yīyuàn dào chēzhàn dā gōngchē yào jǐ zhàn?",
      "pinyin_numeric": "cong2 yi1yuan4 dao4 che1zhan4 da1 gong1che1 yao4 ji3 zhan4",
      "translation_en": "How many stops is it by bus from the hospital to the station?",
      "translation_ko": "병원에서 역까지 버스로 몇 정거장인가요?"
    },
    {
      "text": "從學校到圖書館走路比較慢，所以我們搭公車。",
      "pinyin": "Cóng xuéxiào dào túshūguǎn zǒulù bǐjiào màn, suǒyǐ wǒmen dā gōngchē.",
      "pinyin_numeric": "cong2 xue2xiao4 dao4 tu2shu1guan3 zou3lu4 bi3jiao4 man4, suo3yi3 wo3men da1 gong1che1",
      "translation_en": "Walking from school to the library is slower, so we take the bus.",
      "translation_ko": "학교에서 도서관까지 걷는 것은 더 느리기 때문에 우리는 버스를 탑니다."
    }
  ]
}
